const newItems = [];

for (const item of $input.all()) {
  // Check common paths: item.json.output.Job OR item.json.Job OR item.json.output
  const jobString = item.json.output?.Job || item.json.Job || item.json.output || "";

  // 1. Skip if empty or contains the "No open positions" string
  if (!jobString || typeof jobString !== 'string' || jobString.includes("No open positions")) {
    continue;
  }

  // 2. Split by new lines
  const lines = jobString.split('\n');

  for (let line of lines) {
    let cleanJob = line.trim();

    // 3. Remove "Job Title:" prefix (case-insensitive)
    cleanJob = cleanJob.replace(/^Job Title:\s*/i, "");

    // 4. Remove Markdown formatting if present (like "1. " or "- ")
    cleanJob = cleanJob.replace(/^(\d+\.\s*|-\s*)/, "");

    if (cleanJob.length > 0) {
      newItems.push({
        json: {
          job: cleanJob
        }
      });
    }
  }
}

return newItems;

